'use strict';

function buildEnvelope(job, metadata = {}) {
  const envelope = { job };
  if (metadata.attempt) {
    envelope.attempt = metadata.attempt;
  }
  if (metadata.traceSampled) {
    envelope.traceSampled = metadata.traceSampled;
  }
  return envelope;
}

module.exports = { buildEnvelope };

repo_files.src/worker_context.js:
'use strict';

function contextFromEnvelope(envelope) {
  return {
    attempt: envelope.attempt || 1,
    traceSampled: envelope.traceSampled || true,
  };
}

module.exports = { contextFromEnvelope };

