'use strict';

function labelForJob(job) {
  return `${job.kind}:${job.id}`;
}

module.exports = { labelForJob };

repo_files.tests/public.test.js:
'use strict';

const test = require('node:test');
const assert = require('node:assert/strict');
const { buildEnvelope } = require('../src/job_envelope');
const { contextFromEnvelope } = require('../src/worker_context');
const { labelForJob } = require('../src/job_labels');

test('ordinary delivery metadata survives the queue boundary', () => {
  const envelope = buildEnvelope({ kind: 'email', id: 'm-17' }, {
    attempt: 3,
    traceSampled: true,
  });
  assert.deepEqual(contextFromEnvelope(envelope), {
    attempt: 3,
    traceSampled: true,
  });
});

test('job labels remain stable', () => {
  assert.equal(labelForJob({ kind: 'email', id: 'm-17' }), 'email:m-17');
});
